+                Button(self.isExpanded ? "Hide details" : "Show details") { self.isExpanded.toggle() }
+                    .buttonStyle(.link)
+                    .font(.footnote)
+            }
+
+            if self.isExpanded {
+                Text(self.display.full)
+                    .font(.footnote)
+                    .textSelection(.enabled)
+                    .fixedSize(horizontal: false, vertical: true)
+            }
+        }
+        .padding(.leading, 2)
+    }
+}

